from flask import Flask, request, jsonify
from google.cloud import firestore
import os

app = Flask(__name__)

# Allow requests from any origin (Access-Control-Allow-Origin - *)
@app.after_request
def after_request(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    return response

# Create a Cloud Firestore client
db = firestore.Client()

# Define a route for our HTTP API
@app.route('/api/<string:method>', methods=['POST'])
def api(method):
    # Get the data from the request body
    data = request.get_json()

    # Check if we have a valid method
    if method not in ['create', 'read', 'update', 'delete']:
        return jsonify({'error': f"Method {method} is not supported."}), 400

    # Call the appropriate method on the Cloud Firestore client
    try:
        result = getattr(db, method)(data)
        return jsonify({'result': result})
    except Exception as e:
        return jsonify({'error': str(e)}), 400